```
using BenchmarkTools
s = randn();
t = ntuple(_->randn(), 4);
v = randn(100);
@btime isinf($s);
@btime any(isinf,$t);
@btime any(isinf,$v);

# before
  3.000 ns (0 allocations: 0 bytes)
  5.200 ns (0 allocations: 0 bytes)
  73.073 ns (0 allocations: 0 bytes)

# after
  3.000 ns (0 allocations: 0 bytes)
  3.300 ns (0 allocations: 0 bytes)
  46.964 ns (0 allocations: 0 bytes)
